def validate(args, output):
    orig = args[0] if args[0] is not None else []
    val = args[1]
    def deser(a):
        if not a:
            return None
        root = [a[0], None, None]
        q = [root]; i = 1
        while q and i < len(a):
            node = q.pop(0)
            if i < len(a):
                if a[i] is not None:
                    node[1] = [a[i], None, None]; q.append(node[1])
                i += 1
            if i < len(a):
                if a[i] is not None:
                    node[2] = [a[i], None, None]; q.append(node[2])
                i += 1
        return root
    root = deser(output)
    if root is None:
        return False
    # in-order traversal
    ino = []
    st, node = [], root
    while st or node:
        while node:
            st.append(node); node = node[1]
        node = st.pop(); ino.append(node[0]); node = node[2]
    # must be a valid BST: strictly increasing in-order (all values distinct here)
    for k in range(1, len(ino)):
        if ino[k] <= ino[k - 1]:
            return False
    # multiset of values == original values plus the inserted val
    expected = sorted([v for v in orig if v is not None] + [val])
    if sorted(ino) != expected:
        return False
    return True

