function validate(args, output) {
    const orig = args[0] === null || args[0] === undefined ? [] : args[0];
    const val = args[1];
    function deser(a) {
        if (!a || a.length === 0) return null;
        const root = [a[0], null, null];
        const q = [root]; let i = 1;
        while (q.length && i < a.length) {
            const node = q.shift();
            if (i < a.length) { if (a[i] !== null) { node[1] = [a[i], null, null]; q.push(node[1]); } i++; }
            if (i < a.length) { if (a[i] !== null) { node[2] = [a[i], null, null]; q.push(node[2]); } i++; }
        }
        return root;
    }
    const root = deser(output);
    if (root === null) return false;
    const ino = [];
    const st = []; let node = root;
    while (st.length || node) {
        while (node) { st.push(node); node = node[1]; }
        node = st.pop(); ino.push(node[0]); node = node[2];
    }
    for (let k = 1; k < ino.length; k++) if (ino[k] <= ino[k - 1]) return false;
    const expected = orig.filter(v => v !== null).concat([val]).sort((a, b) => a - b);
    const got = ino.slice().sort((a, b) => a - b);
    if (got.length !== expected.length) return false;
    for (let k = 0; k < got.length; k++) if (got[k] !== expected[k]) return false;
    return true;
}

