class Solution:
    def insertIntoBST(self, root, val):
        if root is None:
            return TreeNode(val)
        cur = root
        while True:
            if val < cur.val:
                if cur.left is None:
                    cur.left = TreeNode(val)
                    break
                cur = cur.left
            else:
                if cur.right is None:
                    cur.right = TreeNode(val)
                    break
                cur = cur.right
        return root

